import{_ as o,c as r,a1 as t,o as n}from"./chunks/framework.DiyHpDmR.js";const u=JSON.parse('{"title":"设计理念","description":"","frontmatter":{},"headers":[],"relativePath":"intro/design.md","filePath":"intro/design.md","lastUpdated":1778079345000}'),i={name:"intro/design.md"};function a(l,e,s,c,d,g){return n(),r("div",null,e[0]||(e[0]=[t('<h1 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h1><p>Firefly 的设计遵循以下核心原则，旨在平衡开发的灵活性与架构的规范性。</p><h2 id="_1-协议优先-schema-first" tabindex="-1">1. 协议优先 (Schema-First) <a class="header-anchor" href="#_1-协议优先-schema-first" aria-label="Permalink to &quot;1. 协议优先 (Schema-First)&quot;">​</a></h2><p>在微服务架构中，<strong>API 契约</strong>是服务间协作的基石。Firefly 坚持使用 <strong>Protobuf</strong> (Protocol Buffers) 作为接口定义语言 (IDL)。</p><ul><li><strong>单一事实来源</strong>：所有的 API 定义、数据结构验证规则都定义在 <code>.proto</code> 文件中。</li><li><strong>代码生成</strong>：通过 <code>buf</code> 等工具自动生成 Server Stub、Client SDK 和 DTO，避免手动编写重复代码。</li><li><strong>语言无关</strong>：一份 Proto 定义可以同时生成 Go, Rust, TypeScript 等多种语言的代码，天然支持多语言生态。</li></ul><h2 id="_2-整洁架构-clean-architecture" tabindex="-1">2. 整洁架构 (Clean Architecture) <a class="header-anchor" href="#_2-整洁架构-clean-architecture" aria-label="Permalink to &quot;2. 整洁架构 (Clean Architecture)&quot;">​</a></h2><p>Firefly 的项目模板（如 <code>go-layout</code>）严格遵循整洁架构的分层原则，实现关注点分离。</p><ul><li><strong>Biz 层（核心业务）</strong>：纯净的业务逻辑，不依赖任何外部实现（如数据库、HTTP 框架）。</li><li><strong>Data 层（数据适配）</strong>：负责数据的持久化和外部接口的调用，通过接口实现 Biz 层的需求。</li><li><strong>Service 层（应用服务）</strong>：负责处理网络请求（gRPC/HTTP），进行参数校验和 DTO 转换，编排 Biz 层逻辑。</li></ul><p>这种设计使得业务逻辑高度可测试、易于维护，并且可以在不修改业务代码的情况下替换底层实现（例如将 MySQL 换成 MongoDB）。</p><h2 id="_3-依赖注入-dependency-injection" tabindex="-1">3. 依赖注入 (Dependency Injection) <a class="header-anchor" href="#_3-依赖注入-dependency-injection" aria-label="Permalink to &quot;3. 依赖注入 (Dependency Injection)&quot;">​</a></h2><p>为了管理复杂的组件依赖关系，Firefly 提倡使用<strong>依赖注入</strong>模式。</p><ul><li><strong>显式依赖</strong>：组件所需的依赖（如数据库连接、配置对象）通过构造函数显式传入，而不是在内部隐式创建或通过全局变量获取。</li><li><strong>编译期安全</strong>：在 Go 语言实现中，我们使用 Google <code>Wire</code> 进行<strong>编译期</strong>依赖注入，在代码编译阶段就能发现依赖缺失的问题，避免运行时错误。</li></ul><h2 id="_4-约定优于配置-convention-over-configuration" tabindex="-1">4. 约定优于配置 (Convention over Configuration) <a class="header-anchor" href="#_4-约定优于配置-convention-over-configuration" aria-label="Permalink to &quot;4. 约定优于配置 (Convention over Configuration)&quot;">​</a></h2><p>Firefly 提供了一套标准化的目录结构和命名规范。</p><ul><li><strong>统一目录</strong>：所有服务都采用相同的 <code>internal/biz</code>, <code>internal/data</code> 等目录结构。</li><li><strong>统一配置</strong>：标准化的 <code>bootstrap.json</code> 引导配置，统一管理服务身份、业务端口、管理端口、sidecar-agent、日志和 telemetry 等启动参数。</li></ul><p>这使得新加入的开发者能够快速上手任何一个基于 Firefly 构建的服务，无需花费大量时间熟悉项目结构。</p><h2 id="_5-极简与可扩展" tabindex="-1">5. 极简与可扩展 <a class="header-anchor" href="#_5-极简与可扩展" aria-label="Permalink to &quot;5. 极简与可扩展&quot;">​</a></h2><p>Firefly 的核心库保持轻量级，不强行绑定过多的第三方库。</p><ul><li><strong>模块化设计</strong>：日志、配置、注册发现和运行时治理都面向稳定契约，裸机 / IDC 可使用 Consul 适配层，云原生环境可切换到 K8s / Istio 运行时，业务代码不直接绑定底层 SDK。</li><li><strong>代码透明</strong>：生成的代码（如 <code>wire_gen.go</code>）也是清晰可读的 Go 代码，没有黑魔法。</li></ul><h2 id="_6-单服务单仓库-repo-per-service" tabindex="-1">6. 单服务单仓库 (Repo-per-Service) <a class="header-anchor" href="#_6-单服务单仓库-repo-per-service" aria-label="Permalink to &quot;6. 单服务单仓库 (Repo-per-Service)&quot;">​</a></h2><p>Firefly 倡导 <strong>单个服务单个仓库</strong> 的代码管理模式，不推荐使用大仓 (Monorepo)。</p><ul><li><strong>独立演进</strong>：每个服务拥有独立的版本控制、CI/CD 流程和依赖管理，避免“牵一发而动全身”。</li><li><strong>公共库抽取</strong>：通用的业务逻辑、工具函数应抽取为独立的 SDK 或 Package（如 <code>go-utils</code>），以库的形式被各个服务引用。</li><li><strong>边界清晰</strong>：物理上的仓库隔离强制划清了服务边界，减少了隐式的代码耦合。</li></ul>',22)]))}const h=o(i,[["render",a]]);export{u as __pageData,h as default};
